@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @bind="searchText"
           @bind:event="oninput"
           @bind:after="OnSearchTextChanged" />

    @if (isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (errorMessage is not null)
    {
        <div class="product-search-error">
            <span>@errorMessage</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (hasSearched && products.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (products.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in products)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                    <div class="product-card-body">
                        <h4>@product.Name</h4>
                        <span class="product-card-price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string searchText = string.Empty;
    private List<Product> products = new();
    private bool isLoading;
    private bool hasSearched;
    private string? errorMessage;

    private CancellationTokenSource? debounceCts;
    private CancellationTokenSource? searchCts;

    private async Task OnSearchTextChanged()
    {
        // Cancel any pending debounce timer.
        debounceCts?.Cancel();
        debounceCts?.Dispose();
        debounceCts = new CancellationTokenSource();
        var debounceToken = debounceCts.Token;

        if (string.IsNullOrWhiteSpace(searchText))
        {
            CancelActiveSearch();
            products = new();
            hasSearched = false;
            errorMessage = null;
            return;
        }

        try
        {
            await Task.Delay(300, debounceToken);
        }
        catch (TaskCanceledException)
        {
            // User typed again before the delay elapsed — nothing to do.
            return;
        }

        await ExecuteSearch(searchText);
    }

    private async Task ExecuteSearch(string query)
    {
        // Cancel any in-flight search so the service stops work we no longer need.
        CancelActiveSearch();
        searchCts = new CancellationTokenSource();
        var token = searchCts.Token;

        isLoading = true;
        errorMessage = null;

        try
        {
            products = await ProductService.SearchAsync(query, token);
            hasSearched = true;
        }
        catch (OperationCanceledException)
        {
            // Search was superseded by a newer query — don't touch UI state.
            return;
        }
        catch (Exception)
        {
            products = new();
            errorMessage = "Something went wrong. Please try again.";
        }
        finally
        {
            // Only clear the loading flag if this search wasn't cancelled.
            if (!token.IsCancellationRequested)
            {
                isLoading = false;
            }
        }
    }

    private async Task RetrySearch()
    {
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            await ExecuteSearch(searchText);
        }
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private void CancelActiveSearch()
    {
        searchCts?.Cancel();
        searchCts?.Dispose();
        searchCts = null;
    }

    public void Dispose()
    {
        debounceCts?.Cancel();
        debounceCts?.Dispose();
        searchCts?.Cancel();
        searchCts?.Dispose();
    }
}

